gen-control.c:script:
const valueProp = dispMeta?.id || 'status';
const labelProp = propMeta?.['graphql:labelProp'] || (valueProp + '_label');
const successVals = ['COMPLETED','APPROVED','RECEIVED','DELIVERED','PAID','SETTLED','HONORED','RETRIED','EXECUTED','COMPUTED','CONFIRMED','RUNNING','MATERIAL_TRANSFERRED','ACTIVE','CLOSED','DONE','SUCCESS'];
const dangerVals = ['REJECTED','CANCELLED','FAILED','DISHONORED','OVERDUE','DOWN','TERMINATED','WRITE_OFF'];
const warningVals = ['ON_HOLD','SUSPENDED','EXPIRED','RETRYING'];
const primaryVals = ['SUBMITTED','IN_PROGRESS','PARTIAL','PARTIALLY_TRANSFERRED','WORK_IN_PROGRESS','PROCESSING','NEGOTIATION','OPEN','UNDER_MAINTENANCE','COLLECTION_PENDING','DISCOUNTED','ENDORSED','ISSUED'];
function quote(v){return "'" + v + "'";}
function inList(vals){return "[" + vals.map(quote).join(",") + "].indexOf(" + valueProp + ") >= 0";}
const expr = inList(successVals) + " ? 'success' : "
    + inList(dangerVals) + " ? 'danger' : "
    + inList(warningVals) + " ? 'warning' : "
    + inList(primaryVals) + " ? 'primary' : 'default'";
return {
    type: "tpl",
    tpl: '<span class="label label-${' + expr + "}"
        + ">"
        + "${" + labelProp + "}</span>"
};
